import{_ as r,o as a,c as o,a7 as e}from"./chunks/framework.BgApuQ2e.js";const s="/images/why-procrastinators-procrastinate/NP-brain.png",p="/images/why-procrastinators-procrastinate/P-brain.png",n="/images/why-procrastinators-procrastinate/IGM-RDM-interacting-1.png",i="/images/why-procrastinators-procrastinate/IGM-RDM-interacting-2.png",c="/images/why-procrastinators-procrastinate/IGM-RDM-interacting-3.png",h="/images/why-procrastinators-procrastinate/IGM-RDM-interacting-4.png",l="/images/why-procrastinators-procrastinate/Dark-Playground.png",g="/images/why-procrastinators-procrastinate/Dark-Playground-people.png",m="/images/why-procrastinators-procrastinate/PM.png",_="/images/why-procrastinators-procrastinate/PM-Scare-1.png",b="/images/why-procrastinators-procrastinate/PM-Scare-2.png",w="/images/why-procrastinators-procrastinate/PM-Scare-3.png",f="/images/why-procrastinators-procrastinate/PDF-Gray-v2.png",A="/images/why-procrastinators-procrastinate/plushies-ad-for-post.jpg",d="/images/why-procrastinators-procrastinate/pinit_fg_en_rect_gray_20.png",q=JSON.parse('{"title":"Why Procrastinators Procrastinate","description":"","frontmatter":{"title":"Why Procrastinators Procrastinate","titleZh":"拖延者为何拖延","date":"2013-10-30T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html","slug":"why-procrastinators-procrastinate"},"headers":[],"relativePath":"posts/why-procrastinators-procrastinate.md","filePath":"posts/why-procrastinators-procrastinate.md","lastUpdated":1782886257000}'),u={name:"posts/why-procrastinators-procrastinate.md"};function y(k,t,P,I,M,D){return a(),o("div",null,[...t[0]||(t[0]=[e('<h1 id="拖延者为何拖延-·-why-procrastinators-procrastinate" tabindex="-1">拖延者为何拖延 · Why Procrastinators Procrastinate <a class="header-anchor" href="#拖延者为何拖延-·-why-procrastinators-procrastinate" aria-label="Permalink to &quot;拖延者为何拖延 · Why Procrastinators Procrastinate&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html</a> · 2013-10-30</p></blockquote><h2 id="pdf-我们把这篇文章做成了一份精致的-pdf-方便打印和离线阅读。在这里购买。-或者看一下预览。" tabindex="-1"><em><strong>PDF:</strong> 我们把这篇文章做成了一份精致的 PDF,方便打印和离线阅读。<a href="https://gum.co/wbw-proc1" target="_blank" rel="noreferrer">在这里购买</a>。(或者看一下<a href="https://waitbutwhy.com/wp-content/uploads/2016/02/why-procrastinators-procrastinate-preview.pdf" target="_blank" rel="noreferrer">预览</a>。)</em> <a class="header-anchor" href="#pdf-我们把这篇文章做成了一份精致的-pdf-方便打印和离线阅读。在这里购买。-或者看一下预览。" aria-label="Permalink to &quot;***PDF:** 我们把这篇文章做成了一份精致的 PDF,方便打印和离线阅读。[在这里购买](https://gum.co/wbw-proc1)。(或者看一下[预览](https://waitbutwhy.com/wp-content/uploads/2016/02/why-procrastinators-procrastinate-preview.pdf)。)*&quot;">​</a></h2><p><strong>pro-cras-ti-na-tion</strong> |prəˌkrastəˈnāSHən, prō-| 名词 拖延或推迟做某事的行为:<em>你的第一条小贴士就是避免拖延</em>。</p><p>谁能想到呢——和拖延症斗争了几十年,最终的解药居然藏在字典里。</p><p><em>避免拖延。</em> 简洁到优雅。</p><p>既然如此,我们也顺便告诉胖子要避免暴食、抑郁的人要避免冷漠,谁去告诉一下搁浅的鲸鱼,它们应该避免离开海洋。</p><p>不,&quot;避免拖延&quot;这种建议只对假性拖延者管用——就是那种会说&quot;我上班时候每天都要刷几次 Facebook,我真是个拖延症患者!&quot;的人。他们也会对真正的拖延者说类似&quot;你别拖延不就完了吗&quot;这种话。</p><p>字典和假性拖延者都不懂的一点是:对真正的拖延者来说,拖延不是一个可选项——他们根本不知道怎么才能不拖延。</p><p>大学里,突如其来的无拘无束的个人自由对我来说就是一场灾难——我什么事都不做,什么时候都不做,什么理由都不行。唯一的例外是我得时不时交论文。我会在前一天晚上写,后来意识到可以通宵写,然后又意识到其实可以等到截止日当天清晨再开始。这种行为达到漫画级别是在我写 90 页的毕业论文时,我直到截止前 72 小时才动笔,结果跑到校医室,医生告诉我手不受控地发麻蜷曲是因为低血糖。(论文是交上去了——不,写得不好。)</p><p>连这篇文章都拖得远超应有时间,因为我花了好几个小时干这种事:看到桌面上有<a href="https://upload.wikimedia.org/wikipedia/commons/d/d5/Jock,_the_Gorilla_(2).jpg" target="_blank" rel="noreferrer">这张图片</a>(是<a href="https://waitbutwhy.com/2013/10/the-primate-awards.html" target="_blank" rel="noreferrer">之前一篇文章</a>留下的),打开它,盯着看好久,想着它能多轻松地把我打趴,然后又想它能不能打过老虎,然后又想狮子和老虎打谁能赢,然后去 Google 搜了一下读了半天(老虎会赢)。我有病。</p><p>要理解拖延者为什么这么爱拖延,我们先看看一个<em>非</em>拖延者的大脑长什么样:</p><p><a href="https://4.bp.blogspot.com/-dID9_Fb3jsQ/Upvh1rjLxYI/AAAAAAAAGb8/fVhfjlj3Pks/s1600/NP+brain.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt=""></a></p><p>挺正常的,对吧?现在,我们再来看看一个拖延者的大脑:</p><p><a href="https://1.bp.blogspot.com/-S6ryaE6HuZg/Upvh2oS7q9I/AAAAAAAAGcI/R2-QDRd6A7o/s1600/P+brain.png" target="_blank" rel="noreferrer"><img src="'+p+'" alt=""></a></p><p>发现什么不同了吗?</p><p>看起来拖延者的大脑里,理性决策者 (Rational Decision-Maker) 身边多了一只宠物——及时行乐猴 (Instant Gratification Monkey)。</p><p>要是理性决策者懂一点养猴子的门道,这本来也没什么——甚至还挺可爱的。但很不幸,这不在他的培训范围内,所以当猴子把他的工作搅得一塌糊涂时,他完全束手无策。</p><p><a href="https://2.bp.blogspot.com/-Itw_OLDmScQ/Upvh0zdThcI/AAAAAAAAGbc/oTJBvQsSgaA/s1600/IGM+RDM+interacting+1.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt=""></a></p><p><a href="https://1.bp.blogspot.com/-TUld_HzbZP8/Upvh1CFYvBI/AAAAAAAAGbo/i3VQRZ3zPjU/s1600/IGM+RDM+interacting+2.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt=""></a></p><p><a href="https://3.bp.blogspot.com/-VG-qHIJJeM4/Upvh1QrCVkI/AAAAAAAAGcE/XwQWbOsUIok/s1600/IGM+RDM+interacting+3.png" target="_blank" rel="noreferrer"><img src="'+c+'" alt=""></a></p><p><a href="https://2.bp.blogspot.com/-CLsCpHveOY0/Upvh1oFtMNI/AAAAAAAAGcA/Bu92QWsX0dQ/s1600/IGM+RDM+interacting+4.png" target="_blank" rel="noreferrer"><img src="'+h+'" alt=""></a></p><p>事实是,及时行乐猴是最不该掌权做决定的生物——他<em>只</em>考虑当下,无视过去的教训,也完全不管未来,他全部的心思都用在把此时此刻的轻松和愉悦最大化上。他对理性决策者的理解,跟理性决策者对他的理解一样少——他心想,我们干嘛要继续慢跑啊,停下来不是更舒服吗?练那个乐器一点都不好玩,我们为什么要练?明明互联网就在那等着我们去玩,为什么还要用电脑工作?他觉得人类都疯了。</p><p>在猴子的世界里,他已经把一切搞明白了——饿了就吃,困了就睡,什么难事都别做,你就是一只相当成功的猴子。拖延者的问题在于,他偏偏活在人类世界里,这让及时行乐猴成了一个极不称职的领航员。而另一边,被训练来做理性决策、而不是被训练来跟人争夺控制权的理性决策者,根本不知道怎么有效反击——他越是失败,越是被脑袋里那个痛苦的拖延者数落,就越对自己感到糟糕。</p><p>一团糟。而猴子一掌权,拖延者就会发现自己在一个叫做「黑暗游乐场 (Dark Playground)」的地方耗掉大量时间。<a href="#footnote-1-502">1</a></p><p>黑暗游乐场 (Dark Playground) 是每个拖延者都再熟悉不过的地方。它是这样一个地方:你在本不该休闲的时候进行着休闲活动。在黑暗游乐场里玩耍其实并不快乐,因为这些快乐完全没有挣来,空气里弥漫着内疚、焦虑、自我厌恶和恐惧。有时理性决策者 (Rational Decision-Maker) 会跺脚发火,拒绝让你浪费时间做那些正常的休闲活动,而即时满足猴子 (Instant Gratification Monkey) 又死活不肯让你工作,于是你就发现自己陷入了一种古怪的炼狱,做着一些没人能赢的怪异活动。<a href="#footnote-2-502">2</a></p><p><a href="https://store.waitbutwhy.com/collections/posters/products/dark-playground-poster-18x24" target="_blank" rel="noreferrer"><img src="'+l+'" alt=""></a></p><p>而可怜的理性决策者只能在一旁闷闷不乐,试图搞清楚自己怎么又让这个本该由他管的人沦落到了<em>这步田地</em>。</p><p><a href="https://store.waitbutwhy.com/collections/posters/products/dark-playground-poster-18x24" target="_blank" rel="noreferrer"><img src="'+g+'" alt=""></a></p><p>既然处境如此,拖延者究竟是怎么把事情做完的呢?</p><p>答案是,有一样东西能把即时满足猴子吓得屁滚尿流:</p><p><a href="https://4.bp.blogspot.com/-MlSCOooBXFE/Upvh3lkFkhI/AAAAAAAAGck/ItaOXl_J2rU/s1600/PM.png" target="_blank" rel="noreferrer"><img src="'+m+'" alt=""></a></p><p>恐慌怪兽 (Panic Monster) 大部分时间都在沉睡,但当截止日期逼近,或者面临公开出丑、职业灾难,或者其他可怕后果时,它就会突然醒来。</p><p><a href="https://1.bp.blogspot.com/-bRsO0-Gbt5I/Upvh2hIjDJI/AAAAAAAAGcs/Bs_y-0os0aY/s1600/PM+Scare+1.png" target="_blank" rel="noreferrer"><img src="'+_+'" alt=""></a></p><p><a href="https://2.bp.blogspot.com/-m06IHIKx56Q/Upvh284PRiI/AAAAAAAAGcg/Dki558dQ1O4/s1600/PM+Scare+2.png" target="_blank" rel="noreferrer"><img src="'+b+'" alt=""></a></p><p><a href="https://4.bp.blogspot.com/-Jjn22OLAd2E/Upvh3ICJbGI/AAAAAAAAGcY/fe37M2hsFiU/s1600/PM+Scare+3.png" target="_blank" rel="noreferrer"><img src="'+w+'" alt=""></a></p><p>平时不可撼动的即时满足猴子,唯独怕恐慌怪兽怕得要死。不然你怎么解释——同一个人,花两周时间都憋不出一篇论文的开头句,却能突然熬通宵、对抗困意、写出八页纸?不然一个超级懒的人怎么会突然开始严格的健身计划,如果不是因为恐慌怪兽对他变得不那么有魅力这件事抓狂了?</p><p>而这些还算是幸运的拖延者——还有一些人甚至连恐慌怪兽都唤不醒,在最绝望的时刻,他们干脆跟猴子一起爬上了树,进入了一种自我毁灭式的停摆状态。</p><p>我们这群人可真够像样的。</p><p>当然,这不是一种活法。哪怕是那种最终还是能把事情搞定、勉强维持着社会人体面的拖延者,也得做出改变。主要原因如下:</p><p><strong>1) 这种状态很不爽。</strong> 拖延者宝贵的时间太多都耗在黑暗游乐场里苦熬了,如果按更合理的节奏做事,这些时间本可以用来享受令人满足、当之无愧的休闲。而且恐慌对谁来说都不是什么乐事。</p><p><strong>2) 拖延者最终会辜负自己。</strong> 他最终碌碌无为,达不到自己应有的高度,这种感觉会日复一日地啃噬他,让他充满悔恨和自我厌恶。</p><p><strong>3) 该做的事可能会做,但想做的事永远做不了。</strong> 就算拖延者从事的是那种恐慌怪兽经常出场的职业,他在工作上能获得成就感——但生活中其他对他来说很重要的事情,比如健身、做精致的大餐、学吉他、写书、阅读,甚至大胆换个职业方向——这些都不会发生,因为恐慌怪兽通常不会管这些事。而正是这类事情拓展了我们的人生体验,让生活更丰富,带给我们大量的幸福感——可对大多数拖延者来说,它们都被远远甩在了身后。</p><h2 id="那么拖延者要怎样改善自己、变得更快乐呢-请看第二部分-如何战胜拖延症。" tabindex="-1">那么拖延者要怎样改善自己、变得更快乐呢?<strong>请看第二部分:<a href="https://waitbutwhy.com/2013/11/how-to-beat-procrastination.html" target="_blank" rel="noreferrer">如何战胜拖延症</a>。</strong> <a class="header-anchor" href="#那么拖延者要怎样改善自己、变得更快乐呢-请看第二部分-如何战胜拖延症。" aria-label="Permalink to &quot;那么拖延者要怎样改善自己、变得更快乐呢?**请看第二部分:[如何战胜拖延症](https://waitbutwhy.com/2013/11/how-to-beat-procrastination.html)。**&quot;">​</a></h2><p><img src="'+f+'" alt=""></p><h2 id="我关于拖延症的-ted-演讲" tabindex="-1"><strong><a href="https://www.ted.com/talks/tim_urban_inside_the_mind_of_a_master_procrastinator" target="_blank" rel="noreferrer">我关于拖延症的 TED 演讲</a></strong> <a class="header-anchor" href="#我关于拖延症的-ted-演讲" aria-label="Permalink to &quot;**[我关于拖延症的 TED 演讲](https://www.ted.com/talks/tim_urban_inside_the_mind_of_a_master_procrastinator)**&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请订阅我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,新文章发布时我们会发给你。</p><h2 id="想支持-wait-but-why-请访问我们的-patreon-页面。" tabindex="-1">想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。 <a class="header-anchor" href="#想支持-wait-but-why-请访问我们的-patreon-页面。" aria-label="Permalink to &quot;想支持 Wait But Why,请访问我们的 **[Patreon 页面](https://patreon.com/waitbutwhy)**。&quot;">​</a></h2><p><strong>两篇相关的 WBW 文章:</strong></p><p><strong><a href="https://waitbutwhy.com/2014/06/taming-mammoth-let-peoples-opinions-run-life.html" target="_blank" rel="noreferrer">为什么你不该在意别人怎么想</a>。</strong> 你大脑另一部分里正在进行的另一场挣扎。来认识一下那头猛犸象。</p><p><strong><a href="https://waitbutwhy.com/2014/10/religion-for-the-nonreligious.html" target="_blank" rel="noreferrer">一种给无信仰者的宗教</a>。</strong> 更深入地剖析你大脑里那只猴子和其他动物的来龙去脉。</p><p>**<br> 反正它们已经在毁掉你的生活了,不如抱着它们一起睡:**</p><p><a href="https://store.waitbutwhy.com/collections/plush-toys" target="_blank" rel="noreferrer"><img src="'+A+'" alt="plushies ad for post"></a></p><hr><ol><li><p>你们当中很多人现在读这篇文章,八成正待在黑暗游乐场里。<a href="#note-1-502">↩</a></p></li><li><p>我在画那张黑暗游乐场插图<em>之前</em>,就在黑暗游乐场里耗了两个小时,因为我害怕要画那个路标,我知道那玩意儿会很难、要画到天荒地老(事实也确实如此)。<a href="#note-2-502">↩</a></p></li></ol><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html&amp;description=Why%20Procrastinators%20Procrastinate" target="_blank" rel="noreferrer"><img src="'+d+'" alt=""></a></p>',57)])])}const v=r(u,[["render",y]]);export{q as __pageData,v as default};
